  value, 
  onChange, 
  onKeyDown, 
  fontSize, 
  autoFocus,
  lang 
}: { 
  value: string, 
  onChange: (e: React.ChangeEvent<HTMLTextAreaElement>) => void, 
  onKeyDown: (e: React.KeyboardEvent) => void, 
  fontSize: number,
  autoFocus?: boolean,
  lang: Language
}) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useLayoutEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [value]);

  return (
    <textarea 
      ref={textareaRef}
      value={value} 
      onChange={onChange} 
      onKeyDown={onKeyDown} 
      className="w-full bg-transparent text-inherit rounded-none p-0 outline-none border-none focus:ring-0 resize-none overflow-hidden leading-relaxed font-inherit min-w-[200px] whitespace-normal break-words" 
      rows={1}
      style={{ fontSize: `${fontSize}px` }} 
      autoFocus={autoFocus} 
      aria-label={t('input.edit_message_content', lang)}
    />
  );
};

interface ThoughtBlockProps {
  text: string;
  lang: Language;
}

const ThoughtBlock: React.FC<ThoughtBlockProps> = ({ text, lang }) => {
  const [isOpen, setIsOpen] = useState(false); 

  return (
    <div className="my-3 border border-gray-200 dark:border-gray-700 rounded-lg bg-gray-50/50 dark:bg-gray-800/30 overflow-hidden">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center gap-2 px-3 py-2 text-xs font-medium text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors"
      >
        <Brain className="w-3.5 h-3.5 text-gray-400" />
        <span>{t('label.thought_process', lang)}</span>
        <div className="ml-auto">
            {isOpen ? <ChevronDown className="w-3.5 h-3.5" /> : <ChevronRight className="w-3.5 h-3.5" />}
        </div>
      </button>
      {isOpen && (
         <div className="px-3 py-2 border-t border-gray-200 dark:border-gray-700 text-xs font-mono text-gray-600 dark:text-gray-400 whitespace-pre-wrap leading-relaxed">
             {text}
         </div>
      )}
    </div>
  );
};

export const ChatMessage: React.FC<ChatMessageProps> = React.memo(({
  msg,
  isEditing,
  isConfirmingDelete,
  isLoading,
  bubbleTransparency,
  textWrapping,
  fontSize,
  showModelName,
  showResponseTimer = false,
  language,
  theme,
  kirbyThemeColor,
  onEditMessage,
  onDeleteMessage,
  onRegenerate,
  setEditingId,
  setConfirmDeleteId,
  startEditing,
  deleteTimerRef,
  onShowToast,
  smoothAnimation = true,
  isLast = false,
  onScrollToBottom,
  avatarVisibility
}) => {
  const [editText, setEditText] = useState(msg.text);
  const [displayedText, setDisplayedText] = useState(msg.text);
  const targetTextRef = useRef(msg.text);
  const animationRef = useRef<number>(0);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  useEffect(() => {
    targetTextRef.current = msg.text;
    if (!smoothAnimation || msg.role !== Role.MODEL || isEditing) {
        setDisplayedText(msg.text);
    }
  }, [msg.text, msg.role, isEditing, smoothAnimation]);

  useEffect(() => {
    if (isEditing) setEditText(msg.text);
  }, [isEditing, msg.text]);

  useEffect(() => {
    if (!smoothAnimation || msg.role !== Role.MODEL || msg.isError || isEditing) return;

    const animate = () => {
      setDisplayedText((current) => {
        const target = targetTextRef.current;
        if (current === target) return current;
        if (current.length > target.length) return target;

        const diff = target.length - current.length;
        let chunk = 2;
        if (diff > 50) chunk = 5;
        if (diff > 100) chunk = 15;
        if (diff > 500) chunk = 50; 

        const nextLen = Math.min(target.length, current.length + chunk);
        const nextText = target.substring(0, nextLen);
        return nextText;
      });
      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);
    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [msg.role, msg.isError, isEditing, smoothAnimation]);

  useLayoutEffect(() => {
      if (isLast && onScrollToBottom && smoothAnimation && msg.role === Role.MODEL && !isEditing) {
          onScrollToBottom();
      }
  }, [displayedText, isLast, onScrollToBottom, smoothAnimation, msg.role, isEditing]);

  const { thoughts, content } = useMemo(() => {
    if (msg.role !== Role.MODEL || isEditing) {
        return { thoughts: [], content: displayedText };
    }
    const thinkRegex = /<think>([\s\S]*?)(?:<\/think>|$)/g;
    const extractedThoughts: string[] = [];
    let match;
    while ((match = thinkRegex.exec(displayedText)) !== null) {
        extractedThoughts.push(match[1]);
    }
    const cleanContent = displayedText.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
    return { thoughts: extractedThoughts, content: cleanContent };
  }, [displayedText, msg.role, isEditing]);

  const cancelEditing = () => { 
    setEditingId(null); 
    setEditText(''); 
    setConfirmDeleteId(null);
  };

  const saveEdit = () => { 
    if (editText.trim() !== msg.text) onEditMessage(msg.id, editText); 
    setEditingId(null); 
    setConfirmDeleteId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => { 
    if (e.key === 'Enter' && !e.shiftKey) { 
      e.preventDefault(); 
      saveEdit(); 
    } 
    if (e.key === 'Escape') cancelEditing(); 
  };

  const handleDeleteClick = () => {
    setEditingId(null);
    if (isConfirmingDelete) {
      onDeleteMessage(msg.id);
      setConfirmDeleteId(null);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    } else {
      setConfirmDeleteId(msg.id);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
      deleteTimerRef.current = setTimeout(() => {
        setConfirmDeleteId(null);
        deleteTimerRef.current = null;
      }, 3000);
    }
  };

  const handleRegenerateClick = () => {
    onRegenerate(msg.id);
    setConfirmDeleteId(null);
  }

  const getWrappingClass = () => {
    switch (textWrapping) {
      case 'forced': return 'whitespace-pre-wrap break-all';
      case 'auto': return 'whitespace-normal break-words';
      case 'default': default: return 'whitespace-pre-wrap break-words';
    }
  };

  const effectiveTransparency = isEditing ? 100 : bubbleTransparency;
  const borderAlpha = 0.5 + (effectiveTransparency / 100) * 0.5;
  const shadowAlpha = (100 - effectiveTransparency) / 100;

  const textShadowStyle = effectiveTransparency < 90 
    ? `0 1px 2px rgba(var(--color-theme-primary-rgb), ${shadowAlpha})` 
    : 'none';

  let backgroundColor;
  if (msg.role === Role.USER) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${effectiveTransparency / 100})`;
  } else if (msg.role === Role.MODEL && !msg.isError) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${(effectiveTransparency / 100) * 0.15})`;
  }

  const animationClass = smoothAnimation ? 'animate-pop-in' : '';
  const wrapperWidthClass = isEditing ? 'w-full max-w-full' : 'max-w-[95%] md:max-w-[85%]'; 
  const bubbleBorderColor = isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`;

  const showAvatar = 
    avatarVisibility === 'always' || 
    (avatarVisibility === 'user-only' && msg.role === Role.USER) ||
    (avatarVisibility === 'model-only' && msg.role === Role.MODEL);

  return (
    <div className={`flex w-full ${containerClass} mx-auto ${msg.role === Role.USER ? 'justify-end' : 'justify-start'} animate-fade-in-up group`}>
        <div className={`flex gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} ${wrapperWidthClass}`}>

            {showAvatar && (
                <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center mt-0.5 overflow-hidden ${msg.role === Role.USER ? 'bg-primary-600' : 'bg-transparent'} ${msg.isError ? 'bg-red-500' : ''}`}>
                    {msg.role === Role.USER ? <User className="w-5 h-5 text-white" /> : <div className="w-full h-full scale-150"><KirbyIcon theme={theme} isThemed={kirbyThemeColor} /></div>}
                </div>
            )}

            <div className={`flex flex-col min-w-0 ${msg.role === Role.USER ? 'items-end' : 'items-start'} w-full`}>
            <div 
                className={`relative px-3 py-2.5 rounded-2xl shadow-sm backdrop-blur-sm transition-all duration-300 w-full max-w-full origin-bottom-left ${animationClass} ${
                    msg.role === Role.USER 
                    ? 'text-white rounded-tr-sm border origin-bottom-right' 
                    : msg.isError 
                        ? 'bg-red-100 dark:bg-red-900/30 border border-red-200 dark:border-red-800 text-red-800 dark:text-red-200 rounded-tl-sm' 
                        : 'border text-gray-800 dark:text-gray-100 rounded-tl-sm'
                }`}
                style={
                    !msg.isError ? { 
                        backgroundColor,
                        borderColor: bubbleBorderColor,
                        textShadow: textShadowStyle
                    } : {}
                }
            >
                {/* Image Grid for Message */}
                {msg.images && msg.images.length > 0 && !isEditing && (
                    <div className="flex flex-wrap gap-2 mb-2">
                        {msg.images.map((img, idx) => (
                            <div key={idx} className="relative group">
                                <img 
                                    src={img} 
                                    alt="Message Attachment" 
                                    className="max-h-64 max-w-full rounded-lg cursor-pointer hover:opacity-90 transition-opacity" 
                                    onClick={() => window.open(img, '_blank')}
                                />
                            </div>
                        ))}
                    </div>
                )}

                {isEditing ? (
                <div className="w-full min-w-[200px]">
                    <AutoResizeTextarea 
                        value={editText} 
                        onChange={(e) => setEditText(e.target.value)} 
                        onKeyDown={handleKeyDown} 
                        fontSize={fontSize}
                        autoFocus
                        lang={language}
                    />
                    <div className="flex justify-end gap-2 mt-2">
                        <button 
                        onClick={cancelEditing} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.cancel', language)}
                        aria-label={t('action.cancel_edit', language)}
                    >
                            <X className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                        <button 
                        onClick={saveEdit} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.confirm', language)}
                        aria-label={t('action.save_edit', language)}
                    >
                            <Save className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                    </div>
                </div>
                ) : (
                <>
                    {msg.isError ? (
                    <div className="flex items-center gap-2"><AlertCircle className="w-4 h-4" /><span>{msg.text}</span></div>
                    ) : (
                    <div className={`markdown-body ${getWrappingClass()}`} style={{ fontSize: `${fontSize}px` }}>
                        {thoughts.length > 0 && (
                            <div className="mb-3 flex flex-col gap-2">
                                {thoughts.map((thought, idx) => (
                                    <ThoughtBlock key={idx} text={thought} lang={language} />
                                ))}
                            </div>
                        )}
                        {/* Only render text content if it exists, otherwise images are handled above */}
                        {(content || (!msg.images || msg.images.length === 0)) && (
                             <ReactMarkdown 
                                remarkPlugins={[remarkGfm, remarkMath]} 
                                rehypePlugins={[rehypeKatex]} 
                                components={{ 
                                    code({node, className, children, ...props}) { 
                                        const match = /language-(\w+)/.exec(className || ''); 
                                        const isInline = !match && !String(children).includes('\n'); 

                                        if (isInline) {
                                          return <code className={className} {...props}>{children}</code>;
                                        }
                                        return (
                                          <CodeBlock 
                                            language={match ? match[1] : 'text'} 
                                            value={String(children).replace(/\n$/, '')} 
                                            theme={theme}
                                            onShowToast={onShowToast}
                                            lang={language}
                                          />
                                        );
                                    },
                                    a({href, children}) {
                                        return (
                                            <a href={href} target="_blank" rel="noopener noreferrer">
                                                {children}
                                                <ExternalLink className="w-3 h-3 inline-block ml-0.5 opacity-70" />
                                            </a>
                                        );
                                    },
                                    img({src, alt}) {
                                        return <img src={src} alt={alt} onClick={() => { if (typeof src === 'string') window.open(src, '_blank'); }} style={{cursor: 'pointer'}} />;
                                    },
                                    input({checked, readOnly}) {
                                        return <input type="checkbox" checked={checked} readOnly={readOnly} className="mr-2 accent-primary-600 rounded w-4 h-4 align-text-bottom cursor-default" />;
                                    }
                                }}
                            >
                                {content}
                            </ReactMarkdown>
                        )}
                    </div>
                    )}
                </>
                )}
            </div>

            <div className="flex flex-wrap items-center gap-x-2 gap-y-1 mt-1 px-1 min-h-[1.5rem]">
                <span className="text-[10px] text-gray-400 dark:text-gray-500 whitespace-nowrap">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                {msg.role === Role.MODEL && !msg.isError && (
                <div className="flex flex-wrap items-center gap-1">
                    {msg.keyIndex && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title="API Key Index">#{msg.keyIndex}</span>
                    )}
                    {showModelName && msg.model && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 break-all max-w-[250px]" title="Model Used">{msg.model}</span>
                    )}
                    {showResponseTimer && msg.executionTime && (
                        <div className="flex items-center gap-0.5 text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title="Response Time">
                            <Clock className="w-2.5 h-2.5" />
                            <span>{t('label.response_time', language).replace('{duration}', (msg.executionTime / 1000).toFixed(1))}</span>
                        </div>
                    )}
                </div>
                )}
                {!isLoading && !isEditing && (
                <div className={`flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity`}>
                    <button 
                    onClick={() => startEditing(msg)} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={t('action.edit', language)}
                    aria-label={t('action.edit_message', language)}
                    >
                    <Edit2 className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleRegenerateClick} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={msg.role === Role.USER ? t('action.regenerate_from_user_message', language) : t('action.regenerate_response', language)}
                    aria-label={t('action.regenerate', language)}
                    >
                    <RefreshCw className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleDeleteClick} 
                    className={`p-4 md:p-1 transition-colors ${isConfirmingDelete ? 'text-red-500 bg-red-50 dark:bg-red-900/20 rounded' : 'text-gray-400 hover:text-red-500'}`}
                    title={isConfirmingDelete ? t('action.confirm_delete', language) : t('action.delete', language)}
                    aria-label={t('action.delete_message', language)}
                    >
                    <Trash2 className="w-3.5 h-3.5" />
                    </button>
                </div>
                )}
            </div>
            </div>
        </div>
    </div>
  );
}, (prev, next) => {
  return (
    prev.msg === next.msg &&
    prev.isEditing === next.isEditing &&
    prev.isConfirmingDelete === next.isConfirmingDelete &&
    prev.isLoading === next.isLoading &&
    prev.bubbleTransparency === next.bubbleTransparency &&
    prev.textWrapping === next.textWrapping &&
    prev.fontSize === next.fontSize &&
    prev.showModelName === next.showModelName &&
    prev.showResponseTimer === next.showResponseTimer &&
    prev.language === next.language &&
    prev.theme === next.theme &&
    prev.kirbyThemeColor === next.kirbyThemeColor &&
    prev.smoothAnimation === next.smoothAnimation &&
    prev.isLast === next.isLast &&
    prev.avatarVisibility === next.avatarVisibility
  );
});

import { Message, KeyConfig, GenerationConfig, ModelProvider, ModelInfo, Language } from "../types";
import { OpenAIService } from "./openaiService";
import { GoogleService } from "./googleService";
import { OllamaService } from "./ollamaService";
import { t } from "../utils/i18n";

/**
 * Service class for handling Multi-Provider LLM interactions.
 * Manages API key rotation, load balancing, and delegates to specific provider services (Google Gemini, OpenAI, or Ollama).
 */
export class LLMService {
  private keys: KeyConfig[] = [];
  private keyIndex: number = 0;
  private keyUsageCount: number = 0;
  private _isCallInProgress: boolean = false; // Lock to prevent concurrent calls

  private openAIService: OpenAIService;
  private googleService: GoogleService;
  private ollamaService: OllamaService;
  private onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void;

  constructor(initialKeys: KeyConfig[], onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void) {
    this.updateKeys(initialKeys);
    this.openAIService = new OpenAIService();
    this.googleService = new GoogleService();
    this.ollamaService = new OllamaService();
    this.onKeyError = onKeyError;
  }

  /**
   * Updates the pool of API keys available for rotation.
   * Resets usage counters if the key list changes significantly.
   */
  public updateKeys(newKeys: KeyConfig[]) {
    this.keys = newKeys;
    if (this.keyIndex >= this.keys.length) {
        this.keyIndex = 0;
        this.keyUsageCount = 0;
    }
  }

  /**
   * Lists available models for a specific key configuration.
   * Supports Google GenAI, OpenAI, and Ollama endpoints.
   */
  public async listModels(keyConfig: KeyConfig): Promise<ModelInfo[]> {
    if (this._isCallInProgress) {
        throw new Error("error.call_in_progress"); // UI will translate this key
    }
    this._isCallInProgress = true;
    try {
        if (keyConfig.provider === 'openai') {
            if (!keyConfig.baseUrl) throw new Error("Base URL is required for OpenAI provider");
            return await this.openAIService.listModels(keyConfig.key, keyConfig.baseUrl);
        } else if (keyConfig.provider === 'ollama') {
            // Allow empty baseUrl (defaults to /ollama-proxy)
            return await this.ollamaService.listModels(keyConfig.baseUrl || '', keyConfig.key);
        } else {
            // Google Implementation
            return await this.googleService.listModels(keyConfig.key);
        }
    } finally {
        this._isCallInProgress = false;
    }
  }

  /**
   * Tests connection for a specific key configuration to ensure validity.
   * Performs a minimal chat generation request or model list check.
   */
  public async testConnection(keyConfig: KeyConfig): Promise<boolean> {
      if (this._isCallInProgress) {
          throw new Error("error.call_in_progress");
      }
      this._isCallInProgress = true;
      try {
          const modelToUse = keyConfig.model || (keyConfig.provider === 'openai' ? 'gpt-3.5-turbo' : 'gemini-2.5-flash');

          try {
              if (keyConfig.provider === 'openai') {
                  if (!keyConfig.baseUrl) return false;
                  return await this.openAIService.testChat(
                      keyConfig.key, 
                      keyConfig.baseUrl, 
                      modelToUse
                  );
              } else if (keyConfig.provider === 'ollama') {
                  // Allow empty baseUrl (defaults to /ollama-proxy)
                  return await this.ollamaService.testConnection(keyConfig.baseUrl || '', keyConfig.key);
              } else {
                  return await this.googleService.testConnection(keyConfig.key, modelToUse);
              }
          } catch (e) {
              return false;
          }
      } finally {
          this._isCallInProgress = false;
      }
  }

  /**
   * Retrieves the next available active API key using a Round-Robin strategy.
   * Handles usage limits per key (Poll Count) and skips rate-limited keys.
   */
  private getNextAvailableKey(lang: Language): KeyConfig {
    const activeKeys = this.keys.filter(k => k.isActive);

    if (activeKeys.length === 0) {
      throw new Error(t('error.no_active_keys', lang));
    }

    // Attempt to find a usable key (not rate limited recently)
    const attempts = activeKeys.length;
    let selectedKey: KeyConfig | null = null;

    // Check next N keys starting from current index
    for (let i = 0; i < attempts; i++) {
        const idx = (this.keyIndex + i) % activeKeys.length;
        const candidate = activeKeys[idx];

        // Check if rate limited and within cooldown period (60s)
        if (candidate.isRateLimited && Date.now() - candidate.lastUsed < 60000) {
            continue; // Skip this key
        }

        // Key is good to use (or at least we should try)
        // Check poll usage limit
        if (i === 0 && this.keyUsageCount >= (candidate.usageLimit || 1)) {
             // Current key exhausted usage limit, force rotate to next
             continue; 
        }

        selectedKey = candidate;
        // Update global index to point to this selected key
        this.keyIndex = idx;
        break;
    }

    // If all keys are rate limited, fallback to the one with oldest usage or just current rotation
    if (!selectedKey) {
        // Fallback: Just rotate to next to try anyway
        this.keyIndex = (this.keyIndex + 1) % activeKeys.length;
        selectedKey = activeKeys[this.keyIndex];
    }

    // Reset usage count if we switched indices from original
    // (Note: this logic is simplified; strict round robin tracks index persistently)
    // Here we just increment usage for the selected key.
    this.keyUsageCount++;

    return selectedKey;
  }

  private getKeyDisplayIndex(id: string): number {
      return this.keys.findIndex(k => k.id === id) + 1;
  }

  /**
   * Helper to map raw error objects/codes to user-friendly messages
   */
  private getErrorMessage(error: any, lang: Language): string {
      const status = error.status || error.statusCode;
      const msg = error.message?.toLowerCase() || '';

      if (status === 401 || msg.includes('401') || msg.includes('invalid api key')) return t('error.invalid_api_key', lang);
      if (status === 402 || msg.includes('402') || msg.includes('billing')) return t('error.billing_required', lang);
      if (status === 403 || msg.includes('403') || msg.includes('permission denied')) return t('error.permission_denied', lang);
      if (status === 404 || msg.includes('404') || msg.includes('not found')) return t('error.model_not_found', lang);
      if (status === 429 || msg.includes('429') || msg.includes('quota') || msg.includes('rate limit')) return t('error.quota_exceeded', lang);
      if (status === 400 || msg.includes('400')) {
          if (msg.includes('safety') || error.isSafety) return t('error.safety_block', lang);
          if (msg.includes('context')) return t('error.context_length_exceeded', lang);
          return t('error.bad_request', lang);
      }
      if (status === 500 || status === 502 || status === 503 || msg.includes('500')) return t('error.server_error', lang);
      if (status === 0 || msg.includes('network') || msg.includes('fetch')) return t('error.network_issue', lang);
      if (msg.includes('refused')) return t('error.connection_refused', lang);

      return error.message || t('error.unexpected_error', lang);
  }

  /**
   * Streams chat response using the next available key and its specific configuration.
   * Handles retries on failure and switches keys automatically.
   */
  public async streamChatResponse(
    _ignoredGlobalModelId: string, 
    history: Message[],
    newMessage: string,
    images: string[] | undefined,
    systemInstruction: string | undefined,
    generationConfig: GenerationConfig,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal,
    lang: Language = 'en'
  ): Promise<{ text: string, usedKeyIndex: number, provider: ModelProvider, usedModel: string }> {

    if (this._isCallInProgress) {
        throw new Error("error.call_in_progress");
    }
    this._isCallInProgress = true;

    try {
        const activeKeysCount = this.keys.filter(k => k.isActive).length;
        // Retry logic: Try at least 2 times per key to handle transient network blips, 
        // but avoid infinite loops. Limit total attempts relative to key count.
        const maxRetries = Math.max(activeKeysCount * 2, 2); 
        let attempts = 0;
        const validHistory = history.filter(msg => (msg.text && msg.text.trim().length > 0) || (msg.images && msg.images.length > 0));

        let lastError: any = null;

        while (attempts < maxRetries) {
            let keyConfig: KeyConfig;
            try {
                keyConfig = this.getNextAvailableKey(lang);
            } catch (e: any) {
                // If getNextAvailableKey throws (e.g. no active keys), stop immediately
                throw e;
            }

            const modelToUse = keyConfig.model || _ignoredGlobalModelId || 'gemini-2.5-flash';

            try {
                let text = "";

                // --- SPECIAL ROUTE: Image Generation (Imagen models) ---
                if (keyConfig.provider === 'google' && modelToUse.toLowerCase().includes('imagen')) {
                     // Google Imagen generation
                     text = await this.googleService.generateImage(
                         keyConfig.key,
                         modelToUse,
                         newMessage
                     );
                } 
                // --- STANDARD ROUTE: Chat/Vision ---
                else if (keyConfig.provider === 'openai') {
                    if (!keyConfig.baseUrl) throw new Error(t('error.base_url_required', lang));
                    text = await this.openAIService.streamChat(
                        keyConfig.key,
                        keyConfig.baseUrl,
                        modelToUse,
                        validHistory,
                        newMessage,
                        images,
                        systemInstruction,
                        generationConfig,
                        onChunk,
                        abortSignal
                    );
                } else if (keyConfig.provider === 'ollama') {
                    // Allow empty baseUrl
                    text = await this.ollamaService.streamChat(
                        keyConfig.baseUrl || '',
                        modelToUse,
                        validHistory,
                        newMessage,
                        images,
                        systemInstruction,
                        generationConfig,
                        keyConfig.key, // Optional API key
                        onChunk,
                        abortSignal
                    );
                } else {
                    // Google Gemini API Call delegated to GoogleService
                    text = await this.googleService.streamChat(
                        keyConfig.key,
                        modelToUse,
                        validHistory,
                        newMessage,
                        images,
                        systemInstruction,
                        generationConfig,
                        onChunk,
                        abortSignal
                    );
                }

                return { 
                    text, 
                    usedKeyIndex: this.getKeyDisplayIndex(keyConfig.id), 
                    provider: keyConfig.provider,
                    usedModel: modelToUse
                };

            } catch (error: any) {
                if (abortSignal?.aborted) throw new Error("Aborted by user");

                lastError = error;

                // Extract Error Code for internal tracking/display
                let errorCode = 'Error';
                let statusCode = error.status || error.statusCode;

                if (statusCode) {
                    errorCode = statusCode.toString();
                } else {
                     const match = error.message?.match(/\b\d{3}\b/);
                     if (match) {
                         errorCode = match[0];
                         statusCode = parseInt(errorCode);
                     }
                     else if (error.message?.includes("Network")) errorCode = "Network";
                }

                // Determine if fatal
                // 401 (Invalid Key), 403 (Permission), 404 (Model Not Found), 400 (Bad Request) are usually configuration errors -> Disable Key
                // 429 (Rate Limit), 500+ (Server), 0 (Network) are transient -> Keep Active but Rate Limit
                let isFatal = false;
                if ([400, 401, 402, 403, 404].includes(statusCode)) {
                    isFatal = true;
                }

                // Specific check for Safety Block (400) - usually prompt specific, not key specific, but treated as error
                if (error.isSafety) {
                    isFatal = false; // Don't disable key for safety blocks
                    // But we should probably throw immediately for safety blocks as rotating won't help?
                    // Actually, let's stop retrying if it's a safety block
                    throw new Error(this.getErrorMessage(error, lang));
                }

                // Notify App
                if (this.onKeyError) {
                    this.onKeyError(keyConfig.id, errorCode, isFatal);
                }

                // Mark inactive or rate-limited locally
                const localKey = this.keys.find(k => k.id === keyConfig.id);
                if (localKey) {
                    if (isFatal) {
                        localKey.isActive = false;
                    } else {
                        localKey.isRateLimited = true;
                        localKey.lastUsed = Date.now();
                    }
                    localKey.lastErrorCode = errorCode;
                }

                // If we ran out of active keys after this failure, stop
                if (this.keys.filter(k => k.isActive).length === 0) {
                     break; 
                }

                attempts++;
                continue;
            }
        }

        // If we exhausted retries or keys
        if (lastError) {
            throw new Error(this.getErrorMessage(lastError, lang));
        }

        throw new Error(t('error.all_keys_failed', lang));
    } finally {
        this._isCallInProgress = false;
    }
  }

  /**
   * Counts tokens for a given context.
   * Returns -1 if provider does not support counting (like generic OpenAI or Ollama) or error occurs.
   */
  public async countTokens(
      keyConfig: KeyConfig,
      history: Message[],
      newMessage: string,
      _ignoredSystemInstruction: string | undefined
  ): Promise<number> {
      if (this._isCallInProgress) {
          throw new Error("error.call_in_progress");
      }
      this._isCallInProgress = true;
      try {
          if (keyConfig.provider !== 'google') return -1;

          return await this.googleService.countTokens(
              keyConfig.key,
              keyConfig.model || 'gemini-2.5-flash',
              history,
              newMessage
          );
      } finally {
          this._isCallInProgress = false;
      }
  }
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message, Role, GenerationConfig, ModelInfo } from "../types";

export class GoogleService {
  /**
   * Lists available models from the Google Gemini API.
   */
  public async listModels(apiKey: string): Promise<ModelInfo[]> {
    try {
        const ai = new GoogleGenAI({ apiKey });
        const response = await ai.models.list();
        const models: ModelInfo[] = [];

        // @ts-ignore - The types for list() response iterator might vary slightly in some SDK versions
        for await (const model of response) {
            const m = model as any;
            if (m.name) {
                const name = m.name.replace('models/', '');
                models.push({
                    name: name,
                    displayName: m.displayName || name,
                    inputTokenLimit: m.inputTokenLimit,
                    outputTokenLimit: m.outputTokenLimit
                });
            }
        }
        // Filter for relevant models (Gemini, Flash, Pro, Thinking, Imagen)
        return models.filter(m => 
            m.name.includes('gemini') || m.name.includes('flash') || m.name.includes('pro') || m.name.includes('thinking') || m.name.includes('imagen')
        );
    } catch (e: any) {
        // Attach status if available in error message or object
        if (e.status === 403 || (e.message && e.message.includes("403"))) {
            const err = new Error("Permission Denied");
            (err as any).status = 403;
            throw err;
        }
        throw e;
    }
  }

  /**
   * Tests connection to Google Gemini API with a minimal generation request.
   */
  public async testConnection(apiKey: string, modelId: string = 'gemini-2.5-flash'): Promise<boolean> {
      try {
          const ai = new GoogleGenAI({ apiKey });
          // If checking Imagen model, use generateImages to test
          if (modelId.includes('imagen')) {
             await ai.models.generateImages({
                 model: modelId,
                 prompt: 'Test',
                 config: { numberOfImages: 1 }
             });
          } else {
             await ai.models.generateContent({
                 model: modelId,
                 contents: 'Test',
             });
          }
          // If we get here without error, the key is valid.
          return true;
      } catch (e) {
          return false;
      }
  }

  /**
   * Counts tokens for a chat history using Google Gemini API.
   */
  public async countTokens(
      apiKey: string,
      modelId: string,
      history: Message[],
      newMessage: string
  ): Promise<number> {
      try {
          const ai = new GoogleGenAI({ apiKey });

          // Filter out invalid messages (error or empty) to match generation logic
          // Note: Token counting might not fully support images yet in the SDK exactly same way, ignoring images for now for simplicity in count
          const validHistory = history.filter(msg => (msg.text && msg.text.trim().length > 0) && !msg.isError);

          const googleHistory = validHistory.map(msg => ({
              role: msg.role === Role.USER ? 'user' : 'model',
              parts: [{ text: msg.text }]
          }));

          const contents = [...googleHistory];

          if (newMessage && newMessage.trim().length > 0) {
              contents.push({
                  role: 'user',
                  parts: [{ text: newMessage }]
              });
          }

          const response = await ai.models.countTokens({
              model: modelId,
              contents: contents,
          });
          return response.totalTokens || 0;
      } catch (error) {
          return -1;
      }
  }

  /**
   * Generates images using Imagen models.
   */
  public async generateImage(apiKey: string, model: string, prompt: string): Promise<string> {
      try {
          const ai = new GoogleGenAI({ apiKey });
          const response = await ai.models.generateImages({
              model: model,
              prompt: prompt,
              config: {
                  numberOfImages: 1,
                  // outputMimeType: 'image/jpeg', // Optional
              }
          });

          // The SDK returns base64 image bytes
          // @ts-ignore - SDK typing might vary slightly
          const imageBytes = response.generatedImages?.[0]?.image?.imageBytes;

          if (imageBytes) {
              // Return as Markdown image
              return `![Generated Image](data:image/png;base64,${imageBytes})`;
          } else {
              throw new Error("No image generated.");
          }
      } catch (e: any) {
         if (e.message && e.message.includes('403')) (e as any).status = 403;
         throw e;
      }
  }

  /**
   * Streams chat response from Google Gemini API.
   */
  public async streamChat(
      apiKey: string, 
      modelId: string, 
      history: Message[], 
      newMessage: string, 
      images: string[] | undefined,
      systemInstruction: string | undefined, 
      config: GenerationConfig,
      onChunk?: (text: string) => void,
      abortSignal?: AbortSignal
  ): Promise<string> {
      try {
        const ai = new GoogleGenAI({ apiKey });

        // Prepare history
        const googleHistory = history.map(msg => {
            const parts: any[] = [];

            // Add images from history if present
            if (msg.images && msg.images.length > 0) {
                 msg.images.forEach(img => {
                     // Convert data URI to inline data
                     // Format: data:image/png;base64,.....
                     const match = img.match(/^data:(.*?);base64,(.*)$/);
                     if (match) {
                         parts.push({
                             inlineData: {
                                 mimeType: match[1],
                                 data: match[2]
                             }
                         });
                     }
                 });
            }

            // Add text part
            if (msg.text) {
                parts.push({ text: msg.text });
            }

            return {
                role: msg.role === Role.USER ? 'user' : 'model',
                parts: parts
            };
        });

        const commonConfig: any = {
            systemInstruction: systemInstruction,
            temperature: config.temperature,
            topP: config.topP,
            topK: config.topK,
            maxOutputTokens: config.maxOutputTokens
        };

        // Apply thinking budget if set and > 0
        if (config.thinkingBudget && config.thinkingBudget > 0) {
            commonConfig.thinkingConfig = { thinkingBudget: config.thinkingBudget };
        }

        const client = ai.chats.create({
            model: modelId,
            config: commonConfig,
            history: googleHistory
        });

        // Prepare new message contents
        const newParts: any[] = [];
        if (images && images.length > 0) {
            images.forEach(img => {
                const match = img.match(/^data:(.*?);base64,(.*)$/);
                if (match) {
                    newParts.push({
                        inlineData: {
                            mimeType: match[1],
                            data: match[2]
                        }
                    });
                }
            });
        }
        if (newMessage) {
            newParts.push({ text: newMessage });
        }

        if (config.stream) {
            // sendMessageStream accepts 'message' which can be string or Part[]
            const resultStream = await client.sendMessageStream({ message: newParts });
            let fullText = '';
            let stopReason = '';

            for await (const chunk of resultStream) {
            if (abortSignal?.aborted) break;

            const response = chunk as GenerateContentResponse;
            const chunkText = response.text;

            if (chunkText) {
                fullText += chunkText;
                if (onChunk) onChunk(fullText);
            } else {
                // If text is undefined/empty, check candidates for finishReason
                const candidate = response.candidates?.[0];
                if (candidate?.finishReason) {
                    stopReason = candidate.finishReason;
                }
            }
            }

            // If we have no text but a stop reason (e.g., SAFETY, RECITATION), display it
            if (!fullText && stopReason) {
                const reasonMessage = `[Response blocked. Reason: ${stopReason}]`;
                if (onChunk) onChunk(reasonMessage);
                const error = new Error(`Safety Block: ${stopReason}`);
                (error as any).status = 400; // Treat as bad request/block
                (error as any).isSafety = true;
                throw error;
            }

            return fullText;
        } else {
            const result = await client.sendMessage({ message: newParts });
            // Handling non-streaming empty response
            if (!result.text && result.candidates?.[0]?.finishReason) {
                 const reason = result.candidates[0].finishReason;
                 const error = new Error(`Safety Block: ${reason}`);
                 (error as any).status = 400;
                 (error as any).isSafety = true;
                 throw error;
            }
            return result.text || '';
        }
      } catch (e: any) {
         // Enhance error object with status code if buried in message
         if (e.message) {
             if (e.message.includes('403')) (e as any).status = 403;
             if (e.message.includes('429')) (e as any).status = 429;
             if (e.message.includes('400')) (e as any).status = 400;
             if (e.message.includes('402')) (e as any).status = 402;
             if (e.message.includes('404')) (e as any).status = 404;
             if (e.message.includes('500')) (e as any).status = 500;
             if (e.message.includes('503')) (e as any).status = 503;
         }
         throw e;
      }
  }
}

import { Message, Role, GenerationConfig, ModelInfo } from "../types";
import { t } from "../utils/i18n"; // Import t for translations

/**
 * Service to handle OpenAI-compatible API interactions.
 */
export class OpenAIService {

  /**
   * Tests the connection by attempting to list models or perform a minimal check.
   */
  public async testConnection(apiKey: string, baseUrl: string): Promise<boolean> {
    try {
      const models = await this.listModels(apiKey, baseUrl);
      return Array.isArray(models);
    } catch (e) {
      return false;
    }
  }

  /**
   * Tests if the key can perform a chat completion.
   */
  public async testChat(apiKey: string, baseUrl: string, modelId: string): Promise<boolean> {
    const cleanUrl = baseUrl.replace(/\/$/, '');
    try {
      const response = await fetch(`${cleanUrl}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`
        },
        body: JSON.stringify({
          model: modelId,
          messages: [{ role: 'user', content: 'Hi' }],
          max_tokens: 1
        })
      });
      return response.ok;
    } catch (e) {
      return false;
    }
  }

  /**
   * Fetches available models from the OpenAI-compatible endpoint.
   */
  public async listModels(apiKey: string, baseUrl: string): Promise<ModelInfo[]> {
    const cleanUrl = baseUrl.replace(/\/$/, '');
    try {
      const response = await fetch(`${cleanUrl}/models`, {
        headers: {
          'Authorization': `Bearer ${apiKey}`
        }
      });

      if (!response.ok) {
        let errorMsg = response.statusText;
        try {
            const errorBody = await response.json();
            if (errorBody.error?.message) errorMsg = errorBody.error.message;
        } catch {
            // fallback to text if json parse fails
            const textBody = await response.text();
            if (textBody) errorMsg = textBody;
        }

        const error = new Error(`OpenAI API Error: ${response.status} - ${errorMsg}`);
        (error as any).status = response.status; 
        throw error;
      }

      const data = await response.json();
      if (data.data && Array.isArray(data.data)) {
        return data.data.map((m: any) => ({
            name: m.id,
            displayName: m.id,
            // OpenAI doesn't standardly expose limits in list models
            inputTokenLimit: 128000, 
            outputTokenLimit: 4096
        })).sort((a: ModelInfo, b: ModelInfo) => a.name.localeCompare(b.name));
      }
      return [];
    } catch (error: any) {
      if (error instanceof TypeError && error.message.includes('Failed to fetch')) { 
          const netErr = new Error("Network Error"); 
          (netErr as any).status = 0;
          throw netErr;
      }
      throw error; 
    }
  }

  /**
   * Streams chat completion from an OpenAI-compatible API.
   */
  public async streamChat(
    apiKey: string,
    baseUrl: string,
    modelId: string,
    history: Message[],
    newMessage: string,
    images: string[] | undefined,
    systemInstruction: string | undefined,
    config: GenerationConfig,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal
  ): Promise<string> {
    const cleanUrl = baseUrl.replace(/\/$/, '');

    // Construct history with images support
    const openAIHistory = history.map(msg => {
      let content: any = msg.text;

      // Check if message has images
      if (msg.images && msg.images.length > 0) {
         content = [];
         if (msg.text) {
             content.push({ type: "text", text: msg.text });
         }
         msg.images.forEach(img => {
             content.push({
                 type: "image_url",
                 image_url: { url: img }
             });
         });
      }

      return {
        role: msg.role === Role.USER ? 'user' : 'assistant',
        content: content
      };
    });

    // Prepend system instruction
    if (systemInstruction) {
      openAIHistory.unshift({ role: 'system' as any, content: systemInstruction });
    }

    // Append current user message
    let newContent: any = newMessage;
    if (images && images.length > 0) {
        newContent = [];
        if (newMessage) {
            newContent.push({ type: "text", text: newMessage });
        }
        images.forEach(img => {
            newContent.push({
                type: "image_url",
                image_url: { url: img }
            });
        });
    }

    openAIHistory.push({ role: 'user', content: newContent });

    const requestBody = {
      model: modelId,
      messages: openAIHistory,
      temperature: config.temperature,
      top_p: config.topP,
      max_tokens: config.maxOutputTokens,
      stream: config.stream
    };

    try { // Outer try-catch for fetch errors
        const response = await fetch(`${cleanUrl}/chat/completions`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${apiKey}`
            },
            body: JSON.stringify(requestBody),
            signal: abortSignal
        });

        if (!response.ok) {
            let errorMsg = response.statusText;
            try {
                const errorBody = await response.json();
                if (errorBody.error?.message) errorMsg = errorBody.error.message;
            } catch {
                const textBody = await response.text();
                if (textBody) errorMsg = textBody;
            }

            const error = new Error(errorMsg);
            (error as any).status = response.status; 
            throw error;
        }

        if (config.stream) {
          const reader = response.body?.getReader();
          const decoder = new TextDecoder("utf-8");
          let fullText = "";

          if (reader) {
            while (true) {
              const { done, value } = await reader.read();
              if (done) break;
              if (abortSignal?.aborted) {
                reader.cancel();
                break;
              }

              const chunk = decoder.decode(value, { stream: true });
              const lines = chunk.split("\n").filter(line => line.trim() !== "");

              for (const line of lines) {
                if (line.startsWith("data: ")) {
                  const dataStr = line.replace("data: ", "").trim();
                  if (dataStr === "[DONE]") break;

                  try {
                    const json = JSON.parse(dataStr);
                    const content = json.choices?.[0]?.delta?.content || "";
                    if (content) {
                      fullText += content;
                      if (onChunk) onChunk(fullText);
                    }
                  } catch (e) {
                    // Ignore parse errors for partial chunks
                  }
                }
              }
            }
          }
          return fullText;
        } else {
          const data = await response.json();
          return data.choices?.[0]?.message?.content || "";
        }
    } catch (error: any) {
        if (error instanceof TypeError && error.message.includes('Failed to fetch')) {
            const netErr = new Error("Network Error"); 
            (netErr as any).status = 0;
            throw netErr;
        }
        throw error; 
    }
  }
}

import { Ollama } from 'ollama/browser';
import { Message, Role, GenerationConfig, ModelInfo } from "../types";
import { t } from "../utils/i18n";

/**
 * Service to handle Ollama API interactions using the official ollama-js library.
 * Configured to always use the local proxy to avoid Mixed Content/CORS issues.
 */
export class OllamaService {

  /**
   * Creates a new Ollama client instance.
   * Forces usage of the local proxy path (/ollama-proxy) derived from window.location.origin.
   */
  private getClient(apiKey?: string): Ollama {
    // Automatically determine host based on current origin to ensure correct proxying
    // This handles both http (localhost) and https (production) correctly via the proxy
    const currentOrigin = window.location.origin;
    const host = `${currentOrigin}/ollama-proxy`;

    const config: { host: string; headers?: Record<string, string> } = {
      host: host
    };

    // If API Key is provided (e.g. for Ollama Cloud), add it as a Bearer token.
    if (apiKey && apiKey.trim()) {
      config.headers = { Authorization: 'Bearer ' + apiKey.trim() };
    }

    return new Ollama(config);
  }

  /**
   * Tests the connection by attempting to list models.
   * Note: baseUrl argument is preserved for interface compatibility but ignored.
   */
  public async testConnection(baseUrl: string, apiKey?: string): Promise<boolean> {
    try {
      const client = this.getClient(apiKey);
      await client.list();
      return true;
    } catch (e) {
      console.warn("Ollama connection test failed:", e);
      return false;
    }
  }

  /**
   * Fetches available models from the Ollama endpoint.
   * Note: baseUrl argument is preserved for interface compatibility but ignored.
   */
  public async listModels(baseUrl: string, apiKey?: string): Promise<ModelInfo[]> {
    try {
      const client = this.getClient(apiKey);
      const response = await client.list();

      // Map Ollama models to App's ModelInfo structure
      return response.models.map((m: any) => ({
          name: m.name,
          displayName: m.name,
          // Ollama list API doesn't explicitly return context limits, default to reasonable values
          inputTokenLimit: 4096, 
          outputTokenLimit: 4096
      })).sort((a: ModelInfo, b: ModelInfo) => a.name.localeCompare(b.name));
    } catch (error: any) {
      console.error("Ollama list models failed:", error);

      // Map status_code to status for consistent error handling in LLMService
      if (error.status_code) {
          (error as any).status = error.status_code;
      }

      if (error instanceof TypeError && error.message.includes('Failed to fetch')) {
          // Provide a more specific hint if it looks like a Mixed Content or CORS issue
          const netErr = new Error("Connection failed. Please check if the Ollama Cloud endpoint is reachable.");
          (netErr as any).status = 0; // Network error
          throw netErr;
      }
      throw error;
    }
  }

  /**
   * Helper to strip base64 header for Ollama (it expects raw base64 usually)
   */
  private extractBase64(dataUri: string): string {
      return dataUri.replace(/^data:image\/[a-z]+;base64,/, "");
  }

  /**
   * Streams chat completion from Ollama API using the library's async generator.
   */
  public async streamChat(
    baseUrl: string, // Ignored
    modelId: string,
    history: Message[],
    newMessage: string,
    images: string[] | undefined,
    systemInstruction: string | undefined,
    config: GenerationConfig,
    apiKey?: string,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal
  ): Promise<string> {
    const client = this.getClient(apiKey);

    // Map App's history to Ollama's expected message format
    const messages = history.map(msg => ({
      role: msg.role === Role.USER ? 'user' : 'assistant',
      content: msg.text,
      // Pass images if present (strip prefix)
      images: msg.images ? msg.images.map(this.extractBase64) : undefined
    }));

    // Prepend system instruction if present
    if (systemInstruction) {
      messages.unshift({ role: 'system', content: systemInstruction, images: undefined });
    }

    // Append the new user message
    messages.push({ 
        role: 'user', 
        content: newMessage,
        images: images ? images.map(this.extractBase64) : undefined
    });

    try {
      const response = await client.chat({
        model: modelId,
        messages: messages,
        stream: true,
        options: {
            temperature: config.temperature,
            top_p: config.topP,
            top_k: config.topK,
            num_predict: config.maxOutputTokens
        }
      });

      let fullText = "";

      // Iterate over the async generator
      for await (const part of response) {
        if (abortSignal?.aborted) {
             // Abort this specific client instance
             client.abort(); 
             break;
        }

        const chunkContent = part.message.content;
        fullText += chunkContent;
        if (onChunk) onChunk(fullText);
      }

      return fullText;

    } catch (error: any) {
      if (error.name === 'AbortError' || abortSignal?.aborted) {
         throw new Error("Aborted by user");
      }

      // Map status_code to status for consistent error handling in LLMService
      if (error.status_code) {
          (error as any).status = error.status_code;
      }

      // Handle connection refused or other network errors generically
      if (error instanceof TypeError || error.message?.includes('Failed to fetch')) {
         const netErr = new Error("Network Error: Failed to fetch. Check connection.");
         (netErr as any).status = 0;
         throw netErr;
      }
      throw error;
    }
  }
}

export const APP_VERSION = '1.6.0';

export enum Role {
  USER = 'user',
  MODEL = 'model'
}

export interface Message {
  id: string;
  role: Role;
  text: string;
  images?: string[]; // Array of base64 data URIs
  timestamp: number;
  isError?: boolean;
  keyIndex?: number; // 1-based index of the key used
  provider?: ModelProvider; // Track which provider generated this
  model?: string; // The specific model used for this message
  executionTime?: number; // Time taken to generate response in ms
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  createdAt: number;
}

export type ModelProvider = 'google' | 'openai' | 'ollama';

export interface KeyGroup {
  id: string;
  name: string;
  isActive?: boolean; // Controls whether the group is enabled during polling
}

export interface KeyConfig {
  id: string;
  key: string;
  provider: ModelProvider; 
  label?: string;
  isActive: boolean;
  usageLimit: number; // Number of requests before switching
  isRateLimited: boolean;
  lastUsed: number;
  baseUrl?: string; // Specific Base URL for this key (OpenAI)
  model?: string;   // Specific Model for this key
  lastErrorCode?: string; // Code of the last error encountered
  groupId?: string; // Optional: ID of the group this key belongs to
}

export enum GeminiModel {
  FLASH = 'gemini-2.5-flash',
  PRO = 'gemini-3-pro-preview',
  FLASH_THINKING = 'gemini-2.5-flash-thinking-preview-01-21',
  IMAGEN = 'imagen-3.0-generate-001'
}

export interface ModelInfo {
  name: string;
  displayName?: string;
  inputTokenLimit?: number;
  outputTokenLimit?: number;
}

export interface SystemPrompt {
  id: string;
  title: string;
  content: string;
  isActive: boolean;
}

export type Theme = 'light' | 'dark' | 'twilight' | 'sky' | 'pink' | 'sunrise' | 'lime' | 'panda' | 'chocolate' | 'vscode-light' | 'vscode-dark';
export type Language = 'en' | 'zh' | 'ja';
export type TextWrappingMode = 'default' | 'forced' | 'auto';
export type AvatarVisibility = 'always' | 'user-only' | 'model-only' | 'never';

export interface SecurityQuestion {
  id: string;
  question: string;
  answer: string;
}

export interface SecurityConfig {
  enabled: boolean;
  password?: string;
  questions: SecurityQuestion[];
  lastLogin: number;
  lockoutDurationSeconds?: number; // New: Duration in seconds for inactivity lockout
}

export interface GenerationConfig {
  temperature: number;
  topP: number;
  topK: number;
  maxOutputTokens: number;
  stream: boolean;
  thinkingBudget?: number; // New: For Gemini 2.5 thinking models
  stripThoughts?: boolean; // New: Strip <think> tags from history to save tokens
}

export interface ScriptConfig {
  inputFilterEnabled: boolean;
  inputFilterCode: string; // The content of the js/ts file
  inputFileName?: string;
  outputFilterEnabled: boolean;
  outputFilterCode: string; // The content of the js/ts file
  outputFileName?: string;
}

export interface AppSettings {
  // Removed global 'model' and 'openAIBaseUrl' as they are now per-key or defaults for new keys
  defaultModel: string; // Default model for new keys
  defaultBaseUrl: string; // Default URL for new OpenAI keys

  systemPrompts: SystemPrompt[];
  theme: Theme;
  language: Language;
  fontSize: number; 
  textWrapping: TextWrappingMode;
  avatarVisibility: AvatarVisibility; // New: Control avatar visibility
  bubbleTransparency: number; // 0-100
  showModelName: boolean; // New: Toggle model name visibility
  kirbyThemeColor: boolean; // New: Toggle kirby icon theme adaptation
  showTokenUsage: boolean; // New: Toggle token usage estimation
  showResponseTimer: boolean; // New: Toggle response execution time display
  smoothAnimation: boolean; // New: Toggle typewriter animation
  historyContextLimit: number; // New: Limit number of past messages sent (0 = unlimited)
  security: SecurityConfig;
  generation: GenerationConfig;
  scripts: ScriptConfig; // New: Script settings

  // API Key Grouping
  enableKeyGrouping?: boolean;
  keyGroups?: KeyGroup[];

  // knownModels removed from AppSettings to separate cache from configuration
  savedModels?: string[]; // Deprecated, kept for interface compat if needed, but logic moved to keys
}

export interface ToastMessage {
  id: string;
  message: string;
  type: 'success' | 'error' | 'info';
}

export interface DialogConfig {
  isOpen: boolean;
  type: 'alert' | 'confirm' | 'input';
  title: string;
  message?: string;
  inputValue?: string;
  inputPlaceholder?: string;
  onConfirm: (value?: string) => void;
  onCancel?: () => void;
}

"use client";

import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { LLMService } from './services/llmService';
import { Message, Role, GeminiModel, AppSettings, KeyConfig, ChatSession, ModelProvider, APP_VERSION, ToastMessage, DialogConfig, ModelInfo } from './types';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInput from './components/ChatInput';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

// Lazy load heavy or hidden-by-default components
const SettingsModal = lazy(() => import('./components/SettingsModal'));
const SecurityLock = lazy(() => import('./components/SecurityLock'));
const MobileMenu = lazy(() => import('./components/MobileMenu'));

// --- Default Configuration ---
const DEFAULT_MODEL = GeminiModel.FLASH;
const STORAGE_KEYS_KEY = 'gemini_omnichat_keys_v4';
const STORAGE_SETTINGS_KEY = 'gemini_omnichat_settings_v8'; 
const STORAGE_SESSIONS_KEY = 'gemini_omnichat_sessions_v1';
const STORAGE_ACTIVE_SESSION_KEY = 'gemini_omnichat_active_session_v1';
const STORAGE_KNOWN_MODELS_KEY = 'gemini_omnichat_known_models_v1';

const ENV_KEY = process.env.API_KEY || '';

const DEFAULT_KNOWN_MODELS: ModelInfo[] = [
    { name: 'gemini-2.5-flash', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-3-pro-preview', inputTokenLimit: 2097152, outputTokenLimit: 8192 },
    { name: 'gemini-2.5-flash-thinking-preview-01-21', inputTokenLimit: 32768, outputTokenLimit: 8192 },
    { name: 'imagen-3.0-generate-001', displayName: 'Imagen 3 (Generate Images)', inputTokenLimit: 0, outputTokenLimit: 0 }
];

const App: React.FC = () => {
  // --- State ---
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string>('');
  const [messages, setMessages] = useState<Message[]>([]);

  const [input, setInput] = useState('');
  const [inputImages, setInputImages] = useState<string[]>([]); // New: Stores base64 images
  const [isLoading, setIsLoading] = useState(false);
  const [isSummarizing, setIsSummarizing] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLocked, setIsLocked] = useState(false);

  const [apiKeys, setApiKeys] = useState<KeyConfig[]>([]);
  const [knownModels, setKnownModels] = useState<ModelInfo[]>(DEFAULT_KNOWN_MODELS);

  const [settings, setSettings] = useState<AppSettings>({
    defaultModel: DEFAULT_MODEL,
    defaultBaseUrl: 'https://api.openai.com/v1',
    systemPrompts: [],
    theme: 'light', // Default to Day/Light
    language: 'zh', // Default to Chinese
    fontSize: 14,
    textWrapping: 'auto', // Default to Auto
    bubbleTransparency: 100, // Default to 100% opacity
    showModelName: true, // Default to true
    kirbyThemeColor: false, // Default to false
    showTokenUsage: false, // Default to false
    showResponseTimer: false, // Default to false
    smoothAnimation: true, // Default to true
    avatarVisibility: 'always', // Default to always show
    historyContextLimit: 0, // Default to 0 (unlimited)
    security: {
        enabled: false,
        questions: [],
        lastLogin: Date.now(),
        lockoutDurationSeconds: 86400 // Default 24 hours in seconds
    },
    generation: {
        temperature: 1.0,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        stream: false, // Default to false (closed)
        thinkingBudget: 0, // Default 0
        stripThoughts: false // Default to false
    },
    scripts: {
        inputFilterEnabled: false,
        inputFilterCode: '',
        outputFilterEnabled: false,
        outputFilterCode: ''
    },
    enableKeyGrouping: false,
    keyGroups: []
  });

  // UI State
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [dialog, setDialog] = useState<DialogConfig>({
      isOpen: false,
      type: 'alert',
      title: '',
      onConfirm: () => {}
  });

  const [llmService, setLlmService] = useState<LLMService | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isProcessingRef = useRef(false);

  // --- Helpers for UI ---
  const addToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
      setToasts(prev => [...prev, { id: uuidv4(), message, type }]);
  };

  const removeToast = (id: string) => {
      setToasts(prev => prev.filter(t => t.id !== id));
  };

  const showDialog = (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
      setDialog({
          isOpen: true,
          type: config.type || 'alert',
          title: config.title,
          message: config.message,
          inputValue: config.inputValue,
          inputPlaceholder: config.inputPlaceholder,
          onConfirm: config.onConfirm,
          onCancel: config.onCancel
      });
  };

  const closeDialog = () => {
      setDialog(prev => ({ ...prev, isOpen: false }));
  };

  // --- Initialization ---
  useEffect(() => {
    // 1. Load Keys & Migration
    const storedKeys = localStorage.getItem(STORAGE_KEYS_KEY);
    const oldKeysV3 = localStorage.getItem('gemini_omnichat_keys_v3');

    // Retrieve old global settings to migrate model/url to keys
    const oldSettingsStr = localStorage.getItem('gemini_omnichat_settings_v5');
    const oldSettings = oldSettingsStr ? JSON.parse(oldSettingsStr) : null;
    const globalModel = oldSettings?.model || DEFAULT_MODEL;
    const globalBaseUrl = oldSettings?.openAIBaseUrl || 'https://api.openai.com/v1';

    let initialKeys: KeyConfig[] = [];

    if (storedKeys) {
      initialKeys = JSON.parse(storedKeys);
    } else if (oldKeysV3) {
      // Migrate v3 keys to v4: Add model and baseUrl to each key
      const parsed = JSON.parse(oldKeysV3);
      initialKeys = parsed.map((k: any) => ({
          ...k,
          model: globalModel,
          baseUrl: k.provider === 'openai' ? globalBaseUrl : ''
      }));
    } else if (ENV_KEY) {
      initialKeys = ENV_KEY.split(',').map(k => k.trim()).filter(Boolean).map(k => ({
        id: uuidv4(),
        key: k,
        provider: 'google' as ModelProvider,
        isActive: true,
        usageLimit: 5, // Default usage limit set to 5
        isRateLimited: false,
        lastUsed: 0,
        model: DEFAULT_MODEL
      }));
    }
    setApiKeys(initialKeys);

    // 2. Load Settings
    const storedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    let loadedSettings = settings;
    let loadedKnownModels = DEFAULT_KNOWN_MODELS;

    // 2.1 Load Known Models from separate cache
    const storedKnownModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (storedKnownModels) {
        try {
            loadedKnownModels = JSON.parse(storedKnownModels);
            // Ensure Imagen is present even if loaded from old cache
            if (!loadedKnownModels.find((m: ModelInfo) => m.name === 'imagen-3.0-generate-001')) {
                loadedKnownModels.push({ name: 'imagen-3.0-generate-001', displayName: 'Imagen 3 (Generate Images)', inputTokenLimit: 0, outputTokenLimit: 0 });
            }
        } catch (e) {
            // console.error("Failed to parse known models from storage", e);
        }
    }

    if (storedSettings) {
      const parsedSettings = JSON.parse(storedSettings);

      // Migration: If knownModels existed in settings but not in separate cache, use it
      if (parsedSettings.knownModels && !storedKnownModels) {
          loadedKnownModels = parsedSettings.knownModels;
      }

      // Remove knownModels from settings object if present
      if ('knownModels' in parsedSettings) {
          delete parsedSettings.knownModels;
      }

      loadedSettings = { ...settings, ...parsedSettings };

      // Ensure lockoutDurationSeconds is set
      if (loadedSettings.security && loadedSettings.security.lockoutDurationSeconds === undefined) {
          loadedSettings.security.lockoutDurationSeconds = 86400; // Default to 24 hours
      }
      // Ensure stream setting exists
      if (loadedSettings.generation && loadedSettings.generation.stream === undefined) {
          loadedSettings.generation.stream = false;
      }
      // Ensure showModelName setting exists
      if (loadedSettings.showModelName === undefined) {
          loadedSettings.showModelName = true;
      }
      // Ensure kirbyThemeColor setting exists
      if (loadedSettings.kirbyThemeColor === undefined) {
          loadedSettings.kirbyThemeColor = false;
      }
       // Ensure showTokenUsage setting exists
       if (loadedSettings.showTokenUsage === undefined) {
          loadedSettings.showTokenUsage = false;
      }
      // Ensure showResponseTimer setting exists
      if (loadedSettings.showResponseTimer === undefined) {
          loadedSettings.showResponseTimer = false;
      }
      // Ensure smoothAnimation setting exists
      if (loadedSettings.smoothAnimation === undefined) {
          loadedSettings.smoothAnimation = true;
      }
      // Ensure avatarVisibility setting exists
      if (loadedSettings.avatarVisibility === undefined) {
          loadedSettings.avatarVisibility = 'always';
      }
      // Ensure historyContextLimit setting exists
      if (loadedSettings.historyContextLimit === undefined) {
          loadedSettings.historyContextLimit = 0;
      }
      // Ensure thinkingBudget exists
      if (loadedSettings.generation && loadedSettings.generation.thinkingBudget === undefined) {
          loadedSettings.generation.thinkingBudget = 0;
      }
      // Ensure stripThoughts exists
      if (loadedSettings.generation && loadedSettings.generation.stripThoughts === undefined) {
          loadedSettings.generation.stripThoughts = false;
      }
      // Ensure key grouping settings exist
      if (loadedSettings.enableKeyGrouping === undefined) {
          loadedSettings.enableKeyGrouping = false;
      }
      if (loadedSettings.keyGroups === undefined) {
          loadedSettings.keyGroups = [];
      }
      // Ensure scripts setting exists
      if (!loadedSettings.scripts) {
          loadedSettings.scripts = {
              inputFilterEnabled: false,
              inputFilterCode: '',
              outputFilterEnabled: false,
              outputFilterCode: ''
          };
      }
    } 
    setSettings(loadedSettings);
    setKnownModels(loadedKnownModels);

    // Init Service - calculate effective keys (masking inactive groups)
    const effectiveKeys = initialKeys.map(k => {
        if (!k.groupId) return k;
        const group = loadedSettings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) {
            return { ...k, isActive: false };
        }
        return k;
    });

    setLlmService(new LLMService(effectiveKeys, (id, errorCode, isFatal = true) => {
        setApiKeys(prev => prev.map(k => {
            if (k.id !== id) return k;
            if (isFatal) {
                // Permanently disable on fatal error
                return { ...k, isActive: false, lastErrorCode: errorCode };
            } else {
                // Temporarily mark rate limited but keep active for future polling
                return { ...k, isRateLimited: true, lastUsed: Date.now(), lastErrorCode: errorCode };
            }
        }));

        if (isFatal) {
            addToast(`${t('error.key_auto_disabled', loadedSettings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
        } else {
            // Optional: notify about rotation/rate limit
            // addToast(`${t('msg.rate_limited', loadedSettings.language)} ${errorCode ? ` (${errorCode})` : ''}`, 'info');
        }
    }));

    // Security
    if (loadedSettings.security.enabled) {
        const lockoutThresholdMs = (loadedSettings.security.lockoutDurationSeconds || 86400) * 1000;
        if (Date.now() - (loadedSettings.security.lastLogin || 0) > lockoutThresholdMs) {
            setIsLocked(true);
        } else {
             const newSettings = { ...loadedSettings, security: { ...loadedSettings.security, lastLogin: Date.now() } };
             setSettings(newSettings);
        }
    }

    // 3. Load Sessions
    const storedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const storedActiveId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (storedSessions) {
      const parsedSessions = JSON.parse(storedSessions) as ChatSession[];
      if (parsedSessions.length > 0) {
        setSessions(parsedSessions);
        const targetId = (storedActiveId && parsedSessions.find(s => s.id === storedActiveId))
          ? storedActiveId 
          : parsedSessions[0].id;
        setActiveSessionId(targetId);
        setMessages(parsedSessions.find(s => s.id === targetId)?.messages || []);
      } else {
        createNewSession();
      }
    } else {
      createNewSession();
    }
  }, []);

  const createNewSession = () => {
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions([newSession]);
    setActiveSessionId(newId);
    setMessages([]);
  };

  // --- Persistence & Key Updates ---
  useEffect(() => {
    // Determine effective keys to pass to LLMService based on Group status
    const effectiveKeys = apiKeys.map(k => {
        if (!k.groupId) return k;
        const group = settings.keyGroups?.find(g => g.id === k.groupId);
        // If group exists and is explicitly inactive (false), disable key for the service
        // We use boolean logic: isActive = key.isActive AND (group.isActive !== false)
        if (group && group.isActive === false) {
            return { ...k, isActive: false };
        }
        return k;
    });

    if (llmService) {
      llmService.updateKeys(effectiveKeys);
    } else {
       // Fallback Init
       setLlmService(new LLMService(effectiveKeys, (id, errorCode, isFatal = true) => {
           setApiKeys(prev => prev.map(k => {
                if (k.id !== id) return k;
                if (isFatal) {
                    return { ...k, isActive: false, lastErrorCode: errorCode };
                } else {
                    return { ...k, isRateLimited: true, lastUsed: Date.now(), lastErrorCode: errorCode };
                }
           }));
           if (isFatal) {
              addToast(`${t('error.key_auto_disabled', settings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
           }
       }));
    }
    localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
  }, [apiKeys, llmService, settings.keyGroups]);

  useEffect(() => {
    localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-chocolate', 'theme-vscode-light', 'theme-vscode-dark');
    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme)) root.classList.add('dark');
  }, [settings]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KNOWN_MODELS_KEY, JSON.stringify(knownModels));
  }, [knownModels]);

  useEffect(() => {
    if (!activeSessionId) return;
    setSessions(prev => {
      const idx = prev.findIndex(s => s.id === activeSessionId);
      if (idx === -1) return prev;
      const updated = [...prev];
      updated[idx] = { ...updated[idx], messages };
      return updated;
    });
  }, [messages, activeSessionId]);

  useEffect(() => {
    if (sessions.length > 0) localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
  }, [sessions]);

  useEffect(() => {
    if (activeSessionId) localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
  }, [activeSessionId]);

  // --- Core Logic ---

  // REFACTORED: Now accepts historyBefore (context) and userMessage (new prompt) separately
  // This avoids ambiguity and prevents duplicate messages in the context.
  const triggerBotResponse = async (historyBefore: Message[], userMessage: Message) => {
    if (!llmService) return;
    setIsLoading(true);

    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const tempBotId = uuidv4();
    const botMessage: Message = {
      id: tempBotId,
      role: Role.MODEL,
      text: '',
      timestamp: Date.now()
    };

    // Optimistic UI update: Previous History + New User Msg + Empty Bot Msg
    setMessages([...historyBefore, userMessage, botMessage]);

    const startTime = Date.now();

    try {
      const systemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');

      // CRITICAL FIX: Ensure history passed to API does NOT contain the new user message.
      let historyForApi = historyBefore.filter(m => m.id !== userMessage.id);

      // Apply "Strip Thoughts" if enabled
      if (settings.generation.stripThoughts) {
        historyForApi = historyForApi.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      // Apply History Context Limit
      let contextToSend = historyForApi;
      if (settings.historyContextLimit > 0 && historyForApi.length > settings.historyContextLimit) {
          contextToSend = historyForApi.slice(-settings.historyContextLimit);
      }

      const { text: fullText, usedKeyIndex, provider, usedModel } = await llmService.streamChatResponse(
        '', // Global model ignored, uses key config
        contextToSend, 
        userMessage.text, // Explicit prompt text
        userMessage.images, // Attached images
        systemInstruction,
        settings.generation,
        (chunkText) => {
           let processedChunk = chunkText;
           if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
               processedChunk = executeFilterScript(
                   settings.scripts.outputFilterCode,
                   chunkText,
                   { role: 'model', history: [...historyBefore, userMessage] }
               );
           }
           setMessages(prev => prev.map(msg => msg.id === tempBotId ? { ...msg, text: processedChunk } : msg));
        },
        controller.signal,
        settings.language
      );

      const executionTime = Date.now() - startTime;

      let processedFinalText = fullText;

      // Regular filter logic
      if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
          processedFinalText = executeFilterScript(
              settings.scripts.outputFilterCode,
              fullText,
              { role: 'model', history: [...historyBefore, userMessage] }
          );
      }

      setMessages(prev => 
        prev.map(msg => 
          msg.id === tempBotId ? { 
              ...msg, 
              text: processedFinalText, 
              keyIndex: usedKeyIndex, 
              provider: provider, 
              model: usedModel, 
              executionTime: executionTime
          } : msg
        )
      );
    } catch (error: any) {
      if (error.message !== "Aborted by user") {
          if (error.message === "error.call_in_progress") {
             addToast(t('error.call_in_progress', settings.language), 'error');
             setMessages(prev => prev.filter(m => m.id !== tempBotId));
          } else {
             const errorMessage: Message = {
                id: uuidv4(),
                role: Role.MODEL,
                text: `${t('action.error', settings.language)}: ${error.message || t('error.unexpected_error', settings.language)}`,
                timestamp: Date.now(),
                isError: true,
                executionTime: Date.now() - startTime
             };
             setMessages(prev => prev.filter(m => m.id !== tempBotId).concat(errorMessage));
          }
      }
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const handleUnlock = () => {
      setIsLocked(false);
      const newSettings = { ...settings, security: { ...settings.security, lastLogin: Date.now() } };
      setSettings(newSettings);
      localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(newSettings));
  };

  const handleSendMessage = async () => {
    if (isLoading || !llmService || isProcessingRef.current) {
        if (isLoading) addToast(t('error.call_in_progress', settings.language), 'error');
        return;
    }

    // Allow sending if there's text OR images
    if (!input.trim() && inputImages.length === 0) return;

    if (apiKeys.filter(k => k.isActive).length === 0) {
      setIsSettingsOpen(true);
      return;
    }

    isProcessingRef.current = true; // Lock

    // Apply Input Filter
    let processedInput = input.trim();
    if (settings.scripts?.inputFilterEnabled && settings.scripts.inputFilterCode) {
        processedInput = executeFilterScript(
            settings.scripts.inputFilterCode, 
            processedInput, 
            { role: 'user', history: messages }
        );
    }

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: processedInput,
      images: inputImages.length > 0 ? [...inputImages] : undefined, // Attach images
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    setInput('');
    setInputImages([]); // Clear images after send

    try {
        await triggerBotResponse(messages, newMessage);
    } finally {
        isProcessingRef.current = false; // Unlock
    }
  };

  const handleGetTokenCount = async (currentInput: string): Promise<number> => {
      if (!llmService || apiKeys.length === 0) return 0;

      const activeKey = apiKeys.find(k => k.isActive);
      if (!activeKey) return 0;

      let contextToSend = messages;
      if (settings.generation.stripThoughts) {
        contextToSend = messages.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      if (settings.historyContextLimit > 0 && contextToSend.length > settings.historyContextLimit) {
          contextToSend = contextToSend.slice(-settings.historyContextLimit);
      }

      const combinedSystemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');

      return await llmService.countTokens(
          activeKey,
          contextToSend,
          currentInput,
          combinedSystemInstruction
      );
  };

  const handleEditMessage = (id: string, newText: string) => {
    setMessages(prev => prev.map(msg => msg.id === id ? { ...msg, text: newText } : msg));
  };

  const handleDeleteMessage = (id: string) => {
    setMessages(prev => prev.filter(msg => msg.id !== id));
  };

  const handleRegenerate = async (id: string) => {
    if (isLoading || !llmService) {
         if (isLoading) addToast(t('error.call_in_progress', settings.language), 'error');
         return;
    }

    const index = messages.findIndex(m => m.id === id);
    if (index === -1) return;
    const targetMsg = messages[index];

    if (targetMsg.role === Role.USER) {
       const historyBefore = messages.slice(0, index);
       await triggerBotResponse(historyBefore, targetMsg);
    } else {
      let userMsgIndex = index - 1;
      while (userMsgIndex >= 0 && messages[userMsgIndex].role !== Role.USER) {
        userMsgIndex--;
      }
      if (userMsgIndex === -1) {
        handleDeleteMessage(id);
        return;
      }
      const historyBefore = messages.slice(0, userMsgIndex);
      const userMsg = messages[userMsgIndex];
      await triggerBotResponse(historyBefore, userMsg);
    }
  };

  const handleNewChat = () => {
    handleStopGeneration();
    createNewSession();
    setIsMobileMenuOpen(false);
  };

  const handleClearChat = () => {
      if (messages.length === 0) return;
      showDialog({
          type: 'confirm',
          title: t('action.clear_chat', settings.language),
          message: t('msg.confirm_clear_chat', settings.language),
          onConfirm: () => {
              handleStopGeneration();
              setMessages([]);
              setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, messages: [] } : s));
          }
      });
  };

  const handleSelectSession = (sessionId: string) => {
    if (sessionId === activeSessionId) { setIsMobileMenuOpen(false); return; }
    handleStopGeneration();
    const session = sessions.find(s => s.id === sessionId);
    if (session) {
      setActiveSessionId(sessionId);
      setMessages(session.messages);
      setInput('');
      setIsMobileMenuOpen(false);
    }
  };

  const handleDeleteSession = (e: React.MouseEvent, sessionId: string) => {
    e.stopPropagation();
    const newSessions = sessions.filter(s => s.id !== sessionId);
    setSessions(newSessions);
    if (activeSessionId === sessionId) {
       handleStopGeneration();
       if (newSessions.length > 0) {
         setActiveSessionId(newSessions[0].id);
         setMessages(newSessions[0].messages);
       } else {
         createNewSession();
       }
    }
  };

  const handleSaveChat = () => {
    const activeSession = sessions.find(s => s.id === activeSessionId);
    const title = activeSession?.title || "Session";
    const safeTitle = title.replace(/[^a-z0-9\u4e00-\u9fa5]/gi, '_').substring(0, 50);
    const chatData = { title, date: new Date().toISOString(), messages };
    const blob = new Blob([JSON.stringify(chatData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `OmniChat-${safeTitle}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleLoadSession = (loadedMessages: any[], title?: string) => {
      handleStopGeneration();
      setMessages(loadedMessages);
      setInput('');
      if (title) {
          setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: title } : s));
      }
      addToast(t('success.chat_import', settings.language), 'success');
  };

  const handleSummarize = async () => {
    if (messages.length === 0 || !llmService) return;
    if (isLoading) {
        addToast(t('error.call_in_progress', settings.language), 'error');
        return;
    }

    setIsSummarizing(true); 
    try {
        const historyText = messages.map(m => `${m.role === Role.USER ? 'User' : 'Model'}: ${m.text}`).join('\n');
        const prompt = t('msg.summarize_prompt', settings.language) + '\n\n' + historyText;
        // Pass empty array for images in summary
        const { text } = await llmService.streamChatResponse('', [], prompt, [], undefined, settings.generation, undefined, undefined, settings.language);
        const newTitle = text.trim().replace(/['"]/g, '').replace(/\.$/, '').replace(/\*\*/g, ''); 
        if (newTitle) {
            setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
            addToast(t('action.ok', settings.language), 'success');
        }
    } catch (error: any) {
        if (error.message === "error.call_in_progress") {
            addToast(t('error.call_in_progress', settings.language), 'error');
        } else {
            addToast(t('msg.summarize_error', settings.language), 'error');
        }
    } finally {
        setIsSummarizing(false);
    }
  };

  const handleRenameSession = () => {
    const currentSession = sessions.find(s => s.id === activeSessionId);
    const currentTitle = currentSession?.title || t('app.title', settings.language);

    showDialog({
        type: 'input',
        title: t('msg.rename_chat', settings.language),
        inputValue: currentTitle,
        onConfirm: (newTitle) => {
            if (newTitle && newTitle.trim()) {
                setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle.trim() } : s));
            }
        }
    });
  };

  const activeKeysCount = apiKeys.filter(k => k.isActive).length;
  const currentSessionTitle = sessions.find(s => s.id === activeSessionId)?.title || t('app.title', settings.language);

  if (isLocked) return (
    <div className={`${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
        <Suspense fallback={<div className="flex h-screen items-center justify-center bg-gray-100 dark:bg-gray-950"></div>}>
            <SecurityLock 
                config={settings.security} 
                onUnlock={handleUnlock} 
                lang={settings.language} 
                theme={settings.theme}
                kirbyThemeColor={settings.kirbyThemeColor}
            />
        </Suspense>
    </div>
  );

  return (
    <div className={`flex h-screen font-sans ${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialog} onClose={closeDialog} lang={settings.language} />

      <div className="flex w-full h-full bg-transparent text-gray-900 dark:text-gray-100 transition-colors duration-300">
        <Sidebar 
            sessions={sessions}
            activeSessionId={activeSessionId}
            activeKeysCount={activeKeysCount}
            language={settings.language}
            theme={settings.theme}
            kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={handleNewChat}
            onSelectSession={handleSelectSession}
            onDeleteSession={handleDeleteSession}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />

        <Suspense fallback={null}>
            <MobileMenu 
                isOpen={isMobileMenuOpen}
                sessions={sessions}
                activeSessionId={activeSessionId}
                language={settings.language}
                onClose={() => setIsMobileMenuOpen(false)}
                onNewChat={handleNewChat}
                onSelectSession={handleSelectSession}
                onDeleteSession={handleDeleteSession}
                onOpenSettings={() => setIsSettingsOpen(true)}
            />
        </Suspense>

        <main className="flex-1 flex flex-col relative h-full min-w-0">
          <Header 
             currentSessionTitle={currentSessionTitle}
             isSummarizing={isSummarizing}
             hasMessages={messages.length > 0}
             language={settings.language}
             onRename={handleRenameSession}
             onSummarize={handleSummarize}
             onOpenMobileMenu={() => setIsMobileMenuOpen(true)}
             onNewChat={handleNewChat}
             onClearChat={handleClearChat}
             onOpenSettings={() => setIsSettingsOpen(true)}
             onSaveChat={handleSaveChat}
             onLoadSession={handleLoadSession}
             onShowToast={addToast}
          />

          <ChatInterface 
              messages={messages} 
              isLoading={isLoading} 
              onEditMessage={handleEditMessage} 
              onDeleteMessage={handleDeleteMessage} 
              onRegenerate={handleRegenerate} 
              language={settings.language} 
              fontSize={settings.fontSize} 
              textWrapping={settings.textWrapping}
              bubbleTransparency={settings.bubbleTransparency}
              showModelName={settings.showModelName}
              showResponseTimer={settings.showResponseTimer}
              theme={settings.theme}
              kirbyThemeColor={settings.kirbyThemeColor}
              onShowToast={addToast}
              smoothAnimation={settings.smoothAnimation}
              avatarVisibility={settings.avatarVisibility}
          />

          <div className="flex-shrink-0 z-20 bg-gradient-to-t from-white via-white/90 to-transparent dark:from-black dark:via-black/90 dark:to-transparent pt-4">
             <ChatInput 
                input={input}
                setInput={setInput}
                inputImages={inputImages}
                setInputImages={setInputImages}
                onSend={handleSendMessage}
                onStop={handleStopGeneration}
                isLoading={isLoading}
                isDisabled={activeKeysCount === 0}
                fontSize={settings.fontSize}
                language={settings.language}
                activeKeysCount={activeKeysCount}
                showTokenUsage={settings.showTokenUsage}
                history={messages}
                historyLimit={settings.historyContextLimit}
                onGetTokenCount={handleGetTokenCount}
                theme={settings.theme}
             />
             <div className="text-center text-[10px] text-gray-400 dark:text-gray-600 pb-1 select-none">
                {t('footer.ai_generated', settings.language)}{APP_VERSION}
             </div>
          </div>
        </main>

        <Suspense fallback={null}>
            <SettingsModal 
                isOpen={isSettingsOpen} 
                onClose={() => setIsSettingsOpen(false)} 
                apiKeys={apiKeys} 
                onUpdateKeys={setApiKeys} 
                settings={settings} 
                onUpdateSettings={setSettings} 
                llmService={llmService}
                onShowToast={addToast}
                onShowDialog={showDialog}
                knownModels={knownModels}
                onUpdateKnownModels={setKnownModels}
            />
        </Suspense>
      </div>
    </div>
  );
};

